// === Infos générales enrichedVars (fusion avec sauvVarSelected) ===

// Gère création/modification d'une variable
// - contrôle du nom
// - initialisation instances (ajout '*' oblig.)
// - initialise proprietes si vide
let enrichedVars = global.get("enrichedVars", "file") || {};
let varSelected = flow.get("varSelected") || null;
let formData = msg.payload;

if (!formData || !formData.nomVarG) {
    msg.info = "❌ Formulaire incomplet ou variable non spécifiée.";
    return null;
}

// --- Normalisation du nom ---
let newName = formData.nomVarG.trim();

// Vérification caractères autorisés
if (!/^[A-Za-z0-9_]+$/.test(newName)) {
    msg.info = `❌ Nom de variable invalide ('${newName}'). Utilise uniquement lettres, chiffres ou '_'`;
    return null;
}

let oldName = varSelected;

// --- Cas création ---
if (!enrichedVars[oldName]) {
    if (enrichedVars[newName]) {
        msg.info = `❌ Impossible de créer '${newName}', une variable existe déjà avec ce nom.`;
        return null;
    }

    enrichedVars[newName] = {
        nomVarG: newName,
        abbrVarG: formData.abbrVarG || "",
        instances: formData.instances
            ? formData.instances.split(",").map(e => e.trim())
            : ["*"],
        descriptionVarG: formData.descriptionVarG || "",
        dateUpdateVarG: new Date().toISOString(),
        proprietes: [
            {
                nom: "defautProp",
                abbr: "def",
                type: "string",
                schema: null,
                valeurs: { "*": "" }
            }
        ]
    };

    flow.set("varSelected", newName);
    global.set("enrichedVars", enrichedVars, "file");

    msg.payload = newName;
    msg.info = `✅ Nouvelle variable créée : ${newName}`;
    return msg;
}

// --- Cas modification ---
let current = enrichedVars[oldName];

// Si le nom change
if (oldName !== newName) {
    if (enrichedVars[newName]) {
        msg.info = `⚠️ '${newName}' existe déjà, impossible de renommer '${oldName}'`;
        return null;
    }

    enrichedVars[newName] = current;
    delete enrichedVars[oldName];
    flow.set("varSelected", newName);
}

// --- Synchronisation des instances ---
let newInstances = formData.instances
    ? formData.instances.split(",").map(e => e.trim())
    : current.instances;
let oldInstances = current.instances || [];

// Synchroniser les valeurs pour toutes les propriétés
(current.proprietes || []).forEach(prop => {
    prop.valeurs = prop.valeurs || {};

    // Ajouter les nouvelles instances avec valeur par défaut
    newInstances.forEach(inst => {
        if (!(inst in prop.valeurs)) {
            switch (prop.type) {
                case "boolean": prop.valeurs[inst] = false; break;
                case "int":
                case "number": prop.valeurs[inst] = 0; break;
                case "array": prop.valeurs[inst] = []; break;
                case "object": prop.valeurs[inst] = {}; break;
                case "date": prop.valeurs[inst] = new Date().toISOString().slice(0, 10); break;
                default: prop.valeurs[inst] = "";
            }
        }
    });

    // Supprimer les valeurs des instances disparues
    oldInstances.forEach(inst => {
        if (!newInstances.includes(inst)) {
            delete prop.valeurs[inst];
        }
    });
});

// --- Mise à jour des infos générales ---
enrichedVars[newName || oldName] = {
    ...enrichedVars[newName || oldName],
    nomVarG: newName,
    abbrVarG: formData.abbrVarG || enrichedVars[newName || oldName].abbrVarG,
    instances: newInstances,
