// vérifier le typage
function castValue(value, type) {
    try {
        switch (type) {
            case 'int':
                const intValue = parseInt(value, 10);
                return isNaN(intValue) ? 0 : intValue; // Valeur par défaut 0 si invalide
            case 'number':
                return Number(value);
            case 'boolean':
                return Boolean(value);
            case 'object':
                return typeof value === 'string' ? JSON.parse(value) : value;
