    }
}


// Fonction : setGlobalVar
// Met à jour une variable globale en vérifiant le type
function setGlobalVar(globalVarName, instance, propName, value) {
    const globalMemory = global.get('enrichedVarsMemory') || {};
    if (!globalMemory[globalVarName] || !globalMemory[globalVarName]._types[propName]) {
        node.error(`Variable ou propriété introuvable : ${globalVarName}.${propName}`, msg);
        return false;
    }

    // Récupérer le type attendu
    const expectedType = globalMemory[globalVarName]._types[propName];
    // Caster la valeur
    const castedValue = castValue(value, expectedType);
    if (castedValue === null) return false;

    // Mettre à jour la valeur
    if (!globalMemory[globalVarName][instance]) {
        globalMemory[globalVarName][instance] = {};
    }
    globalMemory[globalVarName][instance][propName] = castedValue;
    global.set('enrichedVarsMemory', globalMemory);
    return true;
}

// Exemple d'utilisation dans un flow
setGlobalVar('DemoVar', 'inst1', 'distance', "120"); // Cast en number

// Fonction : generateFlowVars (comme précédemment)
function generateFlowVars(globalVarName, instance) {
    const globalMemory = global.get('enrichedVarsMemory') || {};
    const flowVars = {};
    const globalVar = globalMemory[globalVarName]?.[instance];
    if (!globalVar) return flowVars;

    for (const [propName, propValue] of Object.entries(globalVar)) {
        if (propName === '_types') continue; // Ignorer les types
        if (typeof propValue === 'object' && propValue !== null && !Array.isArray(propValue)) {
            for (const [subPropName, subPropValue] of Object.entries(propValue)) {
                flowVars[`${globalVarName}_${propName}_${subPropName}`] = subPropValue;
            }
        } else {
            flowVars[`${globalVarName}_${propName}`] = propValue;
        }
    }
    return flowVars;
}

// Exemple d'utilisation
const flowVars = generateFlowVars('SensorConfig', 'capteur1');
msg.flowVars = flowVars;
return msg;

// 🔄 Fonctions utilitaires existantes
const storeDefault = "default";
const storeFile = "file";

// 🔄 Valeur par défaut selon le type
function defaultForType(type) {
    switch (type) {
        case "boolean": return false;
        case "int": case "number": return 0;
        case "array": return [];
        case "object": return {};
        case "date": return new Date().toISOString().slice(0, 10);
        default: return "";
    }
}

// 🔄 Conversion string → typé
function convertFromString(value, type) {
    if (value === null || value === undefined) return defaultForType(type);
    try {
        switch (type) {
            case "int": return parseInt(value, 10);
            case "number": return parseFloat(value);
            case "boolean": return (value === true || value === "true");
            case "string": return String(value);
            case "array": return Array.isArray(value) ? value : JSON.parse(value);
            case "object": return typeof value === "object" ? value : JSON.parse(value);
            case "date": return new Date(value);
            default: return value;
        }
    } catch (err) {
        node.error(`Erreur de conversion (${type}): ${err.message} (valeur: ${value})`, msg);
        return defaultForType(type);
    }
}

// 🔄 Conversion typé → string/JSON
function convertToString(value, type) {
    if (value === null || value === undefined) return "";
    try {
        switch (type) {
            case "array":
            case "object":
                return JSON.stringify(value);
            default:
                return String(value);
        }
    } catch (err) {
        node.error(`Erreur de sérialisation (${type}): ${err.message}`, msg);
        return String(value);
    }
}

// 🔄 Fonction principale : chargeEnrichedVarsToMemory
function chargeEnrichedVarsToMemory() {
    // Supprimer enrichedVars du stockage par défaut
    global.set("enrichedVars", undefined, storeDefault);

    // Charger enrichedVars depuis le fichier
    let enrichedVars = global.get("enrichedVars", storeFile) || {};
    if (Object.keys(enrichedVars).length === 0) {
        node.error("⚠️ Aucune donnée enrichedVars trouvée dans le stockage fichier.", msg);
        node.status({ fill: "red", shape: "ring", text: "Échec : données manquantes" });
        return false;
    }

    // Initialiser la structure en mémoire globale
    let globalMemory = {};

    // Parcourir chaque variable globale
    for (const [varName, varData] of Object.entries(enrichedVars)) {
        // Initialiser la structure pour cette variable
        globalMemory[varName] = {
            _types: {},               // Stockage des types
            _instances: varData.instances || ["*"]  // Liste des instances
        };

        // Stocker les types de chaque propriété
        for (const prop of varData.proprietes || []) {
            globalMemory[varName]._types[prop.nomP] = prop.typeP;
        }

        // Stocker les valeurs par instance
        for (const instance of varData.instances || ["*"]) {
            globalMemory[varName][instance] = {};
            for (const prop of varData.proprietes || []) {
                // Récupérer la valeur ou une valeur par défaut
                let value = prop.valeurs?.[instance];
                if (value === undefined || value === null) {
                    value = defaultForType(prop.typeP);
                } else {
                    // Convertir la valeur selon son type
                    value = convertFromString(value, prop.typeP);
                }
                globalMemory[varName][instance][prop.nomP] = value;
            }
        }
    }

    // Sauvegarder en mémoire globale
    global.set("enrichedVarsMemory", globalMemory, storeDefault);
    node.status({ fill: "green", shape: "dot", text: "✅ enrichedVars chargé en mémoire" });
    node.send({ payload: "Chargement terminé" });
    return true;
}

// 🔄 Appel de la fonction (déclenché par le nœud)
chargeEnrichedVarsToMemory();

